import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,d as n}from"./app-8955ab6e.js";const i={},d=n(`<h1 id="文本处理" tabindex="-1"><a class="header-anchor" href="#文本处理" aria-hidden="true">#</a> 文本处理</h1><h2 id="awk" tabindex="-1"><a class="header-anchor" href="#awk" aria-hidden="true">#</a> awk</h2><p>​<code>awk</code>​是一种用于文本处理和数据抽取的强大命令行工具。它基于模式匹配和动作执行的原则，允许您在文本文件中查找特定模式并执行相应的操作。</p><p>​<code>awk</code>​的基本语法为：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;pattern { action }&#39;</span> input_file
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>以下是一些常见的 <code>awk</code>​ 选项及案例说明</p><h3 id="列抽取" tabindex="-1"><a class="header-anchor" href="#列抽取" aria-hidden="true">#</a> <strong>列抽取</strong></h3><p>从文本文件中抽取指定的列。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;{print $2}&#39;</span> data.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这个命令从名为 <code>data.txt</code>​ 的文本文件中，每行提取第二列的数据并输出。</p><blockquote><ul><li><p><code>$2</code>​ 表示第二列。列的计数是从 1 开始的。</p></li><li><p><code>$0</code>​ 表示整行内容。</p></li></ul></blockquote><h3 id="特殊变量" tabindex="-1"><a class="header-anchor" href="#特殊变量" aria-hidden="true">#</a> 特殊变量</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;END {print NR}&#39;</span> file.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这个命令在名为 <code>file.txt</code>​ 的文件结束时输出文件的总行数。</p><blockquote><ol><li>​​<code>NR</code>​ 表示当前行号</li><li><code>NF</code>​ 表示当前行中字段（或列）的数量</li><li>​**<code>FS</code><strong>​</strong>（字段分隔符）**：表示字段之间的分隔符。默认情况下，<code>FS</code>​ 的值是空格或制表符（<code>\\t</code>​）。你可以使用 <code>-F</code>​ 命令行选项来改变字段分隔符。</li><li>​**<code>RS</code><strong>​</strong>（记录分隔符）**：表示记录（行）之间的分隔符。默认情况下，<code>RS</code>​ 的值是换行符（<code>\\n</code>​）。你可以使用 <code>-F</code>​ 命令行选项来改变记录分隔符。</li><li>​**<code>OFS</code><strong>​</strong>（输出字段分隔符）**：表示输出时字段之间的分隔符。默认情况下，<code>OFS</code>​ 的值与 <code>FS</code>​ 相同。</li><li>​**<code>ORS</code><strong>​</strong>（输出记录分隔符）**：表示输出时记录之间的分隔符。默认情况下，<code>ORS</code>​ 的值是换行符（<code>\\n</code>​）。</li><li>​**<code>FILENAME</code>**​：表示当前正在处理的文件的名称。</li></ol></blockquote><h3 id="自定义分隔符" tabindex="-1"><a class="header-anchor" href="#自定义分隔符" aria-hidden="true">#</a> <strong>自定义分隔符</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token parameter variable">-F</span> <span class="token string">&#39;:&#39;</span> <span class="token string">&#39;{print $1, $7}&#39;</span> /etc/passwd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用冒号作为字段分隔符，提取 <code>/etc/passwd</code>​ 文件的第一列（用户名）和第七列（用户的登录Shell）。</p><blockquote><p>默认使用空格作为字段分隔符，<code>-F</code>​ 选项用于指定字段分隔符。</p></blockquote><h3 id="自定义输出分隔符" tabindex="-1"><a class="header-anchor" href="#自定义输出分隔符" aria-hidden="true">#</a> <strong>自定义输出分隔符</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;BEGIN {OFS=&quot;\\t&quot;} {print $1, $2}&#39;</span> data.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>设置输出分隔符为制表符，然后每行输出第一、第二和第三列的数据，用制表符分隔。</p><blockquote><p>默认使用空格作为输出分隔符。可以使用内置的 <code>OFS</code>​ 变量来自定义输出分隔符。</p></blockquote><h3 id="自定义变量参数" tabindex="-1"><a class="header-anchor" href="#自定义变量参数" aria-hidden="true">#</a> 自定义变量参数</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token parameter variable">-v</span> <span class="token assign-left variable">OFS</span><span class="token operator">=</span><span class="token string">&quot;:&quot;</span> <span class="token string">&#39;{print $1, $2, $3}&#39;</span> data.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>设置输出分隔符，输出的每列字段之间用<code>:</code>​分割</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token parameter variable">-v</span> <span class="token assign-left variable">math_weight</span><span class="token operator">=</span><span class="token number">0.6</span> <span class="token parameter variable">-v</span> <span class="token assign-left variable">eng_weight</span><span class="token operator">=</span><span class="token number">0.4</span> <span class="token string">&#39;{ total = ($2 * math_weight) + ($3 * eng_weight); print $1, &quot;Total:&quot;, total }&#39;</span> grades.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>设置数学成绩的权重为0.6，英语成绩的权重为0.4，然后计算每个学生的总成绩</p><h3 id="格式化输出" tabindex="-1"><a class="header-anchor" href="#格式化输出" aria-hidden="true">#</a> <strong>格式化输出</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;{printf &quot;Name: %-10s Age: %2d\\n&quot;, $1, $3}&#39;</span> data.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>将名为 <code>data.txt</code>​ 的文件中的第一列（姓名）和第三列（年龄）格式化输出，确保名字占据10个字符的宽度，年龄占据2个字符的宽度。</p><blockquote><ul><li>​<code>%</code>​：表示格式化字符串的起始标记。</li><li>​<code>-</code>​：表示左对齐文本。如果没有 <code>-</code>​，则默认是右对齐。</li><li>​<code>10</code>​：表示字段的宽度。在这里，它指定字符串字段占据的总宽度为 10 个字符。</li><li>​<code>s/d</code>​：表示字符串的数据类型。</li></ul></blockquote><h3 id="初始块-结束块" tabindex="-1"><a class="header-anchor" href="#初始块-结束块" aria-hidden="true">#</a> 初始块/结束块</h3><p>只在第一次和最后一次执行</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;BEGIN {
    print &quot;Student Scores:&quot;
    print &quot;----------------&quot;
}
{
    print &quot;Student:&quot;, $1, &quot;Scores:&quot;, $2
}
END {
    print &quot;----------------&quot;
    print &quot;End of Student Scores&quot;
}&#39;</span> student_scores.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用 <code>BEGIN</code>​ 块在处理开始时输出提示信息，然后在每行数据处理时只输出每个学生的名字和成绩字段。最后，我们使用 <code>END</code>​ 块在处理结束时输出结束信息。</p><blockquote><p>​<code>BEGIN</code>​ 块来在处理开始时执行一些操作；<code>END</code>​ 块来在处理结束时执行一些操作。</p></blockquote><h3 id="条件结构" tabindex="-1"><a class="header-anchor" href="#条件结构" aria-hidden="true">#</a> <strong>条件结构</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;{
    if ($2 &gt; 50000) {
        category = &quot;High&quot;
    } else if ($2 &gt; 30000) {
        category = &quot;Medium&quot;
    } else {
        category = &quot;Low&quot;
    }
    print $1, &quot;:&quot;, category
}&#39;</span> employees.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用 <code>if</code>​、<code>else if</code>​ 和 <code>else</code>​ 条件语句根据薪水水平将员工分为不同的分类，并打印出结果。</p><h3 id="循环结构" tabindex="-1"><a class="header-anchor" href="#循环结构" aria-hidden="true">#</a> 循环结构</h3><h4 id="for​​-循环" tabindex="-1"><a class="header-anchor" href="#for​​-循环" aria-hidden="true">#</a> <strong><code>for</code><strong>​</strong>​ 循环</strong></h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;BEGIN { sum = 0 } { sum += $1 } END { print &quot;Sum:&quot;, sum }&#39;</span> numbers.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>​<code>BEGIN</code>​ 部分用于初始化变量 <code>sum</code>​，然后每行的数字会被加到 <code>sum</code>​ 中，最后 <code>END</code>​ 部分打印出总和。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;{ 
    total = 0 
    for (i = 2; i &lt;= NF; i++) { 
        total += $i 
    } 
    print $1, &quot;Total:&quot;, total 
}&#39;</span> student_scores.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>遍历从第二个字段开始的每个字段，并将它们相加以计算学生的总分。然后，我们使用 <code>print</code>​ 命令输出每个学生的姓名和总分。</p><h4 id="while循环" tabindex="-1"><a class="header-anchor" href="#while循环" aria-hidden="true">#</a> while循环</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;{
    total += $2
    count++
}
END {
    avg = total / count
    print &quot;Average:&quot;, avg
    print &quot;Students above average:&quot;
    while (getline &lt; &quot;scores.txt&quot; &gt; 0) {
        if ($2 &gt; avg) {
            print $1, $2
        }
    }
}&#39;</span> scores.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在while循环中，使用 getline 函数从文件中逐行读取数据，然后通过条件语句判断分数是否高于平均分，并输出相应的学生信息。</p><h3 id="行处理" tabindex="-1"><a class="header-anchor" href="#行处理" aria-hidden="true">#</a> <strong>行处理</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;/^host1/&#39;</span> logfile.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>输出所有以 &quot;host1&quot; 开头的日志记录</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># -i 忽略大小写</span>
<span class="token function">awk</span> <span class="token string">&#39;/error/i&#39;</span> logfile.txt
<span class="token comment"># 设置参数，忽略大小写</span>
<span class="token function">awk</span> <span class="token string">&#39;BEGIN {IGNORECASE=1} /error/&#39;</span> logfile.txt
<span class="token comment"># 将内容转换为小写，然后使用 ~(匹配运算符)进行正则匹配</span>
 <span class="token function">awk</span> <span class="token string">&#39;tolower($0) ~ /error/ &#39;</span> logfile.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>匹配日志中所有包含error的行，忽略大小写</p><blockquote><p>可以在模式部分使用斜杠 <code>/</code>​ 包裹正则表达式。</p></blockquote><h3 id="关联数组" tabindex="-1"><a class="header-anchor" href="#关联数组" aria-hidden="true">#</a> <strong>关联数组</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;!seen[$0]++&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>去重，只输出第一次出现的行</p><blockquote><ol><li>关联数组在 <code>awk</code>​ 中可以用于统计每行出现的次数，是因为它们提供了一种将键（索引）与值关联起来的方式。在这种情况下，数组的键是文本行的内容，而值是该行出现的次数。</li></ol></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;{ seen[$0]++ } END { for (record in seen) print record, &quot;Count:&quot;, seen[record] }&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>统计每行出现的次数</p><h3 id="个性化定制搜索模式" tabindex="-1"><a class="header-anchor" href="#个性化定制搜索模式" aria-hidden="true">#</a> <strong>个性化定制搜索模式</strong></h3><p>假设您有一个名为 <code>data.txt</code>​ 的文本文件，其中包含以下内容：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>this is wang ,not wan
that is chen, not che 
this is chen ,and wang ,not wan che 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>提取is后面的第一个单词，和not 后面的第一个单词</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">awk</span> <span class="token string">&#39;{match($0,/.+is([^,]+).+not(.+)/,a);print a[1],a[2]}&#39;</span> <span class="token builtin class-name">test</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p>a[1]代表第一个（）的内容，a[2]代表第二个（）的内容，以此类推</p></blockquote><h2 id="grep" tabindex="-1"><a class="header-anchor" href="#grep" aria-hidden="true">#</a> grep</h2><p>​<code>grep</code>​ 是一个在 Unix-like 系统上常用的命令行工具，用于在文本文件中搜索指定的字符串模式，并返回匹配的行。它的名字来自于 &quot;Global Regular Expression Print&quot;，表示它的原始目的是全局地搜索正则表达式并打印匹配的结果。</p><p>​<code>grep</code>​ 的基本语法为：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> pattern <span class="token punctuation">[</span>file <span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>以下是一些常见的 <code>grep</code>​ 选项及案例说明：</p><h3 id="基本用法" tabindex="-1"><a class="header-anchor" href="#基本用法" aria-hidden="true">#</a> <strong>基本用法</strong></h3><p>在单个文件中搜索指定字符串模式，并返回匹配的行。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token string">&quot;pattern&quot;</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="在多个文件中搜索" tabindex="-1"><a class="header-anchor" href="#在多个文件中搜索" aria-hidden="true">#</a> <strong>在多个文件中搜索</strong></h3><p>在多个文件中搜索指定字符串模式。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token string">&quot;pattern&quot;</span> file1 file2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="递归搜索" tabindex="-1"><a class="header-anchor" href="#递归搜索" aria-hidden="true">#</a> <strong>递归搜索</strong></h3><p>在指定目录及其子目录中递归搜索。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-r</span> <span class="token string">&quot;pattern&quot;</span> directory
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="忽略大小写" tabindex="-1"><a class="header-anchor" href="#忽略大小写" aria-hidden="true">#</a> <strong>忽略大小写</strong></h3><p>不区分大小写地搜索。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-i</span> <span class="token string">&quot;pattern&quot;</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="显示行号" tabindex="-1"><a class="header-anchor" href="#显示行号" aria-hidden="true">#</a> <strong>显示行号</strong></h3><p>显示匹配行的行号。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-n</span> <span class="token string">&quot;pattern&quot;</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="显示匹配的上下文" tabindex="-1"><a class="header-anchor" href="#显示匹配的上下文" aria-hidden="true">#</a> <strong>显示匹配的上下文</strong></h3><p>显示匹配行及其上下文的内容。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-C</span> <span class="token number">2</span> <span class="token string">&quot;pattern&quot;</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="只显示匹配的计数" tabindex="-1"><a class="header-anchor" href="#只显示匹配的计数" aria-hidden="true">#</a> <strong>只显示匹配的计数</strong></h3><p>显示匹配的行数而不显示具体内容。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-c</span> <span class="token string">&quot;pattern&quot;</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="反向搜索" tabindex="-1"><a class="header-anchor" href="#反向搜索" aria-hidden="true">#</a> <strong>反向搜索</strong></h3><p>显示不包含指定字符串模式的行。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-v</span> <span class="token string">&quot;pattern&quot;</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="使用正则表达式" tabindex="-1"><a class="header-anchor" href="#使用正则表达式" aria-hidden="true">#</a> <strong>使用正则表达式</strong></h3><p>使用正则表达式进行更复杂的模式匹配。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-E</span> <span class="token string">&quot;regex pattern&quot;</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="sed" tabindex="-1"><a class="header-anchor" href="#sed" aria-hidden="true">#</a> sed</h2><p>​<code>sed</code>​（Stream Editor）是一个流式文本编辑器，用于在输入流中进行文本替换、转换和编辑。它主要用于在命令行中进行文本处理，支持各种文本操作，如替换、插入、删除、打印等。<code>sed</code>​ 使用基于正则表达式的模式匹配来定位和操作文本。</p><p>以下是一些常用的 <code>sed</code>​ 案例介绍：</p><h3 id="替换文本内容" tabindex="-1"><a class="header-anchor" href="#替换文本内容" aria-hidden="true">#</a> <strong>替换文本内容</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sed</span> <span class="token string">&#39;s/old_text/new_text/&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这会在输入文件中将第一个匹配的 &quot;old_text&quot; 替换为 &quot;new_text&quot;</p><blockquote><p>上述命令仅在标准输出中显示结果，不会更改原始文件。</p></blockquote><h3 id="保存修改到新文件" tabindex="-1"><a class="header-anchor" href="#保存修改到新文件" aria-hidden="true">#</a> <strong>保存修改到新文件</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sed</span> <span class="token string">&#39;s/pattern/replacement/&#39;</span> input.txt <span class="token operator">&gt;</span> output.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>将修改后的内容输出到一个新文件中</p><h3 id="编辑原文件" tabindex="-1"><a class="header-anchor" href="#编辑原文件" aria-hidden="true">#</a> <strong>编辑原文件</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sed</span> <span class="token parameter variable">-i</span> <span class="token string">&#39;s/pattern/replacement/&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用 <code>-i</code>​ 参数可以直接在原始文件上进行编辑，而不需要创建新文件</p><h3 id="替换所有匹配" tabindex="-1"><a class="header-anchor" href="#替换所有匹配" aria-hidden="true">#</a> <strong>替换所有匹配</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sed</span> <span class="token string">&#39;s/old_text/new_text/g&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>加上 <code>g</code>​ 标志将替换所有匹配的 &quot;old_text&quot;。</p><h3 id="只打印匹配的行" tabindex="-1"><a class="header-anchor" href="#只打印匹配的行" aria-hidden="true">#</a> <strong>只打印匹配的行</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sed</span> <span class="token parameter variable">-n</span> <span class="token string">&#39;/pattern/p&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>​<code>-n</code>​ 参数表示只输出匹配的行，<code>/pattern/p</code>​ 表示匹配包含 &quot;pattern&quot; 的行并打印出来。</p><h3 id="删除匹配的行" tabindex="-1"><a class="header-anchor" href="#删除匹配的行" aria-hidden="true">#</a> <strong>删除匹配的行</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sed</span> <span class="token string">&#39;/pattern/d&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>删除包含 &quot;pattern&quot; 的行。</p><h3 id="插入新行" tabindex="-1"><a class="header-anchor" href="#插入新行" aria-hidden="true">#</a> <strong>插入新行</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 在第二行之前插入一行文本</span>
<span class="token function">sed</span> <span class="token string">&#39;2i\\New line to insert&#39;</span> input.txt
<span class="token comment"># 在第二行之后插入一行文本</span>
<span class="token function">sed</span> <span class="token string">&#39;2a\\New line to after&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在固定的行前后插入数据</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 在包含hello的上一行插入up</span>
<span class="token function">sed</span> <span class="token parameter variable">-i</span> <span class="token string">&#39;/hello/i\\up&#39;</span> input.txt
<span class="token comment"># 在包含hello的下一行插入down</span>
<span class="token function">sed</span> <span class="token parameter variable">-i</span> <span class="token string">&#39;/hello/a\\down&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在匹配的行前后插入数据，有多个匹配行，那么在每一行上面或者下面都插入内容</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 在最后一行之后追加一行文本</span>
<span class="token function">sed</span> <span class="token string">&#39;$a\\New line to append&#39;</span> input.txt
<span class="token comment"># 最后一行之前追加一行文本</span>
<span class="token function">sed</span> <span class="token string">&#39;$i\\New line to append&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在文件最后一行的前后插入数据， <code>$</code>​ 表示最后一行。</p><h3 id="使用正则表达式匹配" tabindex="-1"><a class="header-anchor" href="#使用正则表达式匹配" aria-hidden="true">#</a> <strong>使用正则表达式匹配</strong></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sed</span> <span class="token string">&#39;s/[0-9]\\+$/REPLACEMENT/&#39;</span> input.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在每一行的结尾匹配一个或多个数字并替换为 &quot;REPLACEMENT&quot;</p><p>‍</p>`,132),t=[d];function r(l,o){return a(),s("div",null,t)}const u=e(i,[["render",r],["__file","文本处理.html.vue"]]);export{u as default};
